"use strict";const newsContainer=document.getElementById("news-container");fetch("/api/news",{method:"GET"}).then(response=>{response.json().then(json=>{json.forEach(news=>{var newsPost=document.createElement("li"),newsLink=document.createElement("a"),newsTime=document.createElement("h6");newsLink.href=`/news/${news.id}`,newsLink.innerText=news.title,newsTime.textContent=`(${moment.utc(news.created_at).fromNow()})`,newsPost.appendChild(newsLink),newsPost.appendChild(newsTime),newsContainer.appendChild(newsPost)})})});